const incoming = $input.first().json || {};
const headers = incoming.headers || {};
const rawBody = incoming.body;
const body =
  rawBody && typeof rawBody === 'object' && rawBody.action !== undefined
    ? rawBody
    : incoming;

const action = body.action || '';
const acceptedActions = new Set(['opened', 'ready_for_review', 'reopened']);
if (!acceptedActions.has(action)) {
  return [];
}

const pr = body.pull_request || {};
const repo = body.repository || {};
const delivery =
  headers['x-github-delivery'] ||
  headers['X-GitHub-Delivery'] ||
  body.delivery ||
  `pr-${pr.number || 'unknown'}-${Date.now()}`;

return [
  {
    json: {
      pr_number: pr.number,
      title: pr.title || '',
      repo_full_name: repo.full_name || 'paperwork-labs/paperwork',
      request_id: String(delivery),
    },
  },
];
